import React from 'react';
import { useAuth } from '../context/AuthContext';
import StudentPanel from './StudentPanel';
import FacultyPanel from './FacultyPanel';
import AdminPanel from './AdminPanel';
import Leaderboard from '../Leaderboard';

const Dashboard = () => {
  const { user, logout } = useAuth();

  const renderPanel = () => {
    switch (user.role) {
      case 'admin': return <AdminPanel />;
      case 'faculty': return <FacultyPanel />;
      case 'student': return <StudentPanel />;
      default: return <p>Unknown role</p>;
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Welcome, {user.name} ({user.role})</h2>
        <button onClick={logout} style={{ background: '#dc3545', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '5px' }}>Logout</button>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        {renderPanel()}
        <Leaderboard />
      </div>
    </div>
  );
};

export default Dashboard;
